func (c *current) onCallArgs1(args any) (any, error) {
	if args == nil {
		return []any{}, nil
	}
	parts := args.([]any)
	first := parts[0]
	rest := parts[1].([]any)
	out := make([]any, 0, 1+len(rest))
	out = append(out, first)
	out = append(out, rest...)
	return out, nil
}

